Set.Top:
function loadItems(xmlPath) {
    var url = './?XMLNAME=/ewa/UPDATE_CFG.xml&ITEMNAME=ItemSelect.LF.M&XML_PATH=' + encodeURIComponent(xmlPath);
    EWA.F.jump(url);
}

Set.Bottom:
// 初始化
function init_xml_select() {
    // 页面加载后自动请求数据
    $.getJSON('./?XMLNAME=/ewa/UPDATE_CFG.xml&ITEMNAME=XmlSelect.LF.M&EWA_AJAX=json&EWA_ACTION=loadData', function(res) {
        if (res && res.success && res.data) {
            renderXmlList(res.data);
        }
    });
}
function renderXmlList(data) {
    var html = '<table class="ewa-table"><thead><tr>'
        + '<th>#</th><th>XML 路径</th><th>Item 数量</th><th>类型分布</th><th>操作</th>'
        + '</tr></thead><tbody>';
    for (var i = 0; i < data.length; i++) {
        var d = data[i];
        var types = '';
        if (d.frameTypes) {
            for (var k in d.frameTypes) {
                types += k + '(' + d.frameTypes[k] + ') ';
            }
        }
        html += '<tr><td>' + (i+1) + '</td>'
            + '<td>' + d.xmlName + '</td>'
            + '<td>' + d.itemCount + '</td>'
            + '<td>' + types + '</td>'
            + '<td><button onclick="loadItems(\'' + d.xmlName + '\')">选择</button></td></tr>';
    }
    html += '</tbody></table>';
    $('#ewa_list_body').html(html);
}
addEvent(window, 'load', init_xml_select);

Set.Script:
// Ajax 调用 UpdateCfgAction 获取 XML 文件列表
String url = "./?XMLNAME=/ewa/UPDATE_CFG.xml&ITEMNAME=XmlSelect.LF.M";
// 后端直接输出 JSON

Set.Top:
var gXmlPath = '@XML_PATH';
var gItemName = '';

function openXItemList() {
    if (!gItemName) { alert('请先选择模板'); return; }
    var url = './?XMLNAME=/ewa/UPDATE_CFG.xml&ITEMNAME=XItemCfg.LF.M&XML_PATH=' + encodeURIComponent(gXmlPath) + '&ITEM_NAME=' + encodeURIComponent(gItemName);
    EWA.F.jump(url);
}
function openSqlList() {
    if (!gItemName) { alert('请先选择模板'); return; }
    var url = './?XMLNAME=/ewa/UPDATE_CFG.xml&ITEMNAME=SqlCfg.LF.M&XML_PATH=' + encodeURIComponent(gXmlPath) + '&ITEM_NAME=' + encodeURIComponent(gItemName);
    EWA.F.jump(url);
}

Set.Bottom:
function init_item_select() {
    $.getJSON('./?XMLNAME=/ewa/UPDATE_CFG.xml&ITEMNAME=ItemSelect.LF.M&EWA_AJAX=json', {
        method: 'listItems',
        XML_PATH: gXmlPath
    }, function(res) {
        if (res && res.success && res.data) {
            renderItemList(res.data);
        } else {
            $('#ewa_list_body').html('<p style="color:red;">加载失败: ' + (res ? res.message : '未知错误') + '</p>');
        }
    });
}
function renderItemList(data) {
    var html = '<table class="ewa-table"><thead><tr>'
        + '<th>#</th><th>模板名称</th><th>中文描述</th><th>英文描述</th>'
        + '<th>XItem 数</th><th>SQL 数</th><th>操作</th>'
        + '</tr></thead><tbody>';
    for (var i = 0; i < data.length; i++) {
        var d = data[i];
        html += '<tr>'
            + '<td>' + (i+1) + '</td>'
            + '<td><a href="javascript:selectItem(\'' + d.name + '\')">' + d.name + '</a></td>'
            + '<td>' + (d.descZh||'') + '</td>'
            + '<td>' + (d.descEn||'') + '</td>'
            + '<td>' + d.xitemCount + '</td>'
            + '<td>' + d.sqlCount + '</td>'
            + '<td><button onclick="selectItem(\'' + d.name + '\')">选择</button></td>'
            + '</tr>';
    }
    html += '</tbody></table>';
    $('#ewa_list_body').html(html);
}
function selectItem(name) {
    gItemName = name;
    $('#lbl_current_item').text(name);
    // 高亮选中行
    $('#ewa_list_body tr').removeClass('selected');
    $('#ewa_list_body tr').each(function() {
        if ($(this).find('td').eq(1).text() === name) {
            $(this).addClass('selected');
        }
    });
}
addEvent(window, 'load', init_item_select);

Set.Top:
var gXmlPath = '@XML_PATH';
var gItemName = '@ITEM_NAME';

function addXItem() {
    var url = './?XMLNAME=/ewa/UPDATE_CFG.xml&ITEMNAME=XItemCfg.F.NM&XML_PATH=' + encodeURIComponent(gXmlPath) + '&ITEM_NAME=' + encodeURIComponent(gItemName);
    EWA.F.jump(url);
}
function editXItem(name) {
    var url = './?XMLNAME=/ewa/UPDATE_CFG.xml&ITEMNAME=XItemCfg.F.NM&XML_PATH=' + encodeURIComponent(gXmlPath) + '&ITEM_NAME=' + encodeURIComponent(gItemName) + '&XITEM_NAME=' + encodeURIComponent(name);
    EWA.F.jump(url);
}
function deleteXItem(name) {
    if (!confirm('确定删除 XItem: ' + name + ' ?')) return;
    $.post('./?XMLNAME=/ewa/UPDATE_CFG.xml&ITEMNAME=XItemCfg.LF.M&EWA_AJAX=json', {
        method: 'deleteXItem',
        XML_PATH: gXmlPath,
        ITEM_NAME: gItemName,
        XITEM_NAME: name
    }, function(res) {
        if (res && res.success) {
            alert('删除成功');
            loadData();
        } else {
            alert('删除失败: ' + (res ? res.message : '未知错误'));
        }
    });
}
function moveXItem(name, dir) {
    $.post('./?XMLNAME=/ewa/UPDATE_CFG.xml&ITEMNAME=XItemCfg.LF.M&EWA_AJAX=json', {
        method: 'moveXItem',
        XML_PATH: gXmlPath,
        ITEM_NAME: gItemName,
        XITEM_NAME: name,
        direction: dir
    }, function(res) {
        if (res && res.success) {
            loadData();
        } else {
            alert(res ? res.message : '移动失败');
        }
    });
}

Set.Bottom:
function loadData() {
    $.getJSON('./?XMLNAME=/ewa/UPDATE_CFG.xml&ITEMNAME=XItemCfg.LF.M&EWA_AJAX=json', {
        method: 'listXItems',
        XML_PATH: gXmlPath,
        ITEM_NAME: gItemName
    }, function(res) {
        if (res && res.success && res.data) {
            renderXItemList(res.data);
        } else {
            $('#ewa_list_body').html('<p style="color:red;">加载失败: ' + (res ? res.message : '未知错误') + '</p>');
        }
    });
}
function renderXItemList(data) {
    var html = '<table class="ewa-table"><thead><tr>'
        + '<th>#</th><th>Name</th><th>Tag</th><th>中文描述</th><th>英文描述</th>'
        + '<th>DataField</th><th>DataType</th><th>必填</th><th>排序</th>'
        + '<th>操作</th>'
        + '</tr></thead><tbody>';
    for (var i = 0; i < data.length; i++) {
        var d = data[i];
        html += '<tr>'
            + '<td>' + (i+1) + '</td>'
            + '<td>' + d.name + '</td>'
            + '<td>' + (d.tag||'') + '</td>'
            + '<td>' + (d.descZh||'') + '</td>'
            + '<td>' + (d.descEn||'') + '</td>'
            + '<td>' + (d.dataField||'') + '</td>'
            + '<td>' + (d.dataType||'') + '</td>'
            + '<td>' + (d.isMustInput=='1'?'是':'') + '</td>'
            + '<td>' + (d.isOrder||'') + '</td>'
            + '<td>'
            + '<button onclick="moveXItem(\''+d.name+'\','up')">↑</button> '
            + '<button onclick="moveXItem(\''+d.name+'\','down')">↓</button> '
            + '<button onclick="editXItem(\''+d.name+'\')">编辑</button> '
            + '<button onclick="deleteXItem(\''+d.name+'\')">删除</button>'
            + '</td></tr>';
    }
    html += '</tbody></table>';
    $('#ewa_list_body').html(html);
}
addEvent(window, 'load', loadData);

Set.Top:
var gXmlPath = '@XML_PATH';
var gItemName = '@ITEM_NAME';
var gXItemName = '@XITEM_NAME';
var gOldXItemName = gXItemName; // 修改时原始名称

function goBack() {
    var url = './?XMLNAME=/ewa/UPDATE_CFG.xml&ITEMNAME=XItemCfg.LF.M&XML_PATH=' + encodeURIComponent(gXmlPath) + '&ITEM_NAME=' + encodeURIComponent(gItemName);
    EWA.F.jump(url);
}

Set.Bottom:
function init_xitem_form() {
    if (gXItemName) {
        // 编辑模式：加载数据
        $.getJSON('./?XMLNAME=/ewa/UPDATE_CFG.xml&ITEMNAME=XItemCfg.F.NM&EWA_AJAX=json', {
            method: 'getXItem',
            XML_PATH: gXmlPath,
            ITEM_NAME: gItemName,
            XITEM_NAME: gXItemName
        }, function(res) {
            if (res && res.success && res.data) {
                fillForm(res.data);
            }
        });
    }
}
function fillForm(data) {
    // 由 EWA 自动绑定，此处可做额外处理
    $('#lbl_xitem').text(data.name || '');
}
// 提交前检查
function do_pos_before_xitem() {
    if (!$('#XITEM_NAME').val()) {
        alert('XItem 名称不能为空');
        return false;
    }
    return true;
}
addEvent(window, 'load', init_xitem_form);

