var gXmlPath = '@XML_PATH';
var gItemName = '@ITEM_NAME';

function addSqlSet() {
    var url = './?XMLNAME=/ewa/UPDATE_CFG.xml&ITEMNAME=SqlCfg.F.NM&XML_PATH=' + encodeURIComponent(gXmlPath) + '&ITEM_NAME=' + encodeURIComponent(gItemName);
    EWA.F.jump(url);
}
function editSqlSet(name) {
    var url = './?XMLNAME=/ewa/UPDATE_CFG.xml&ITEMNAME=SqlCfg.F.NM&XML_PATH=' + encodeURIComponent(gXmlPath) + '&ITEM_NAME=' + encodeURIComponent(gItemName) + '&SQL_NAME=' + encodeURIComponent(name);
    EWA.F.jump(url);
}
function addScriptSet() {
    var url = './?XMLNAME=/ewa/UPDATE_CFG.xml&ITEMNAME=ScriptCfg.F.NM&XML_PATH=' + encodeURIComponent(gXmlPath) + '&ITEM_NAME=' + encodeURIComponent(gItemName);
