}
function editScriptSet(name) {
    var url = './?XMLNAME=/ewa/UPDATE_CFG.xml&ITEMNAME=ScriptCfg.F.NM&XML_PATH=' + encodeURIComponent(gXmlPath) + '&ITEM_NAME=' + encodeURIComponent(gItemName) + '&SCRIPT_NAME=' + encodeURIComponent(name);
