function deleteSqlSet(name) {
    if (!confirm('确定删除 SqlSet: ' + name + ' ?\n注意: 请先确认没有 ActionSet 引用它。')) return;
    $.post('./?XMLNAME=/ewa/UPDATE_CFG.xml&ITEMNAME=SqlCfg.LF.M&EWA_AJAX=json', {
        method: 'deleteSqlSet',
        XML_PATH: gXmlPath,
        ITEM_NAME: gItemName,
        SQL_NAME: name
    }, function(res) {
        if (res && res.success) {
            alert('删除成功');
            loadData();
        } else {
            alert('删除失败: ' + (res ? res.message : '未知错误'));
        }
    });
}

Set.Bottom:
function loadData() {
    $.getJSON('./?XMLNAME=/ewa/UPDATE_CFG.xml&ITEMNAME=SqlCfg.LF.M&EWA_AJAX=json', {
        method: 'listActions',
        XML_PATH: gXmlPath,
        ITEM_NAME: gItemName
    }, function(res) {
        if (res && res.success && res.data) {
            renderActions(res.data);
        } else {
            $('#ewa_list_body').html('<p style="color:red;">加载失败: ' + (res ? res.message : '未知错误') + '</p>');
        }
    });
}
function renderActions(data) {
    var html = '';

    // ===== ActionSet 部分 =====
    html += '<h3>ActionSet (执行流程)</h3>';
    html += '<table class="ewa-table"><thead><tr>'
        + '<th>Action 类型</th><th>调用列表</th>'
        + '</tr></thead><tbody>';
    if (data.actions && data.actions.length > 0) {
        for (var i = 0; i < data.actions.length; i++) {
            var a = data.actions[i];
            var callsHtml = '';
            for (var j = 0; j < a.calls.length; j++) {
                var c = a.calls[j];
                var badge = c.callType == 'SqlSet' ? 'SQL' : 'Script';
                callsHtml += '<span style="display:inline-block;margin:2px;padding:2px 6px;background:#e8f4fd;border-radius:3px;">'
                    + badge + ': ' + c.callName
                    + (c.test ? ' <i>(条件: ' + c.test + ')</i>' : '')
                    + '</span> ';
            }
            html += '<tr><td><b>' + a.type + '</b></td><td>' + callsHtml + '</td></tr>';
        }
    } else {
        html += '<tr><td colspan="2" style="color:#999;">无 ActionSet 配置</td></tr>';
    }
    html += '</tbody></table>';

    // ===== SqlSet 部分 =====
    html += '<h3 style="margin-top:20px;">SqlSet (SQL 定义)</h3>';
    html += '<table class="ewa-table"><thead><tr>'
        + '<th>#</th><th>SQL 名称</th><th>类型</th><th>事务</th>'
        + '<th>SQL 预览</th><th>被引用</th><th>操作</th>'
        + '</tr></thead><tbody>';
    if (data.sqlSets && data.sqlSets.length > 0) {
        for (var i = 0; i < data.sqlSets.length; i++) {
            var s = data.sqlSets[i];
            var refBy = '';
            if (s.referencedBy && s.referencedBy.length > 0) {
                for (var k = 0; k < s.referencedBy.length; k++) {
                    refBy += s.referencedBy[k] + ' ';
                }
            } else {
                refBy = '<span style="color:#999;">未被引用</span>';
            }
            html += '<tr>'
                + '<td>' + (i+1) + '</td>'
                + '<td><b>' + s.name + '</b></td>'
                + '<td>' + s.sqlType + '</td>'
                + '<td>' + s.transType + '</td>'
                + '<td><pre style="max-height:60px;overflow:hidden;margin:0;">' + (s.sqlPreview||'') + '</pre></td>'
                + '<td>' + refBy + '</td>'
                + '<td>'
                + '<button onclick="editSqlSet(\''+s.name+'\')">编辑</button> '
                + '<button onclick="deleteSqlSet(\''+s.name+'\')">删除</button>'
                + '</td></tr>';
        }
    } else {
        html += '<tr><td colspan="7" style="color:#999;">无 SqlSet 配置</td></tr>';
    }
    html += '</tbody></table>';

    // ===== ScriptSet 部分 =====
    html += '<h3 style="margin-top:20px;">ScriptSet (脚本定义)</h3>';
    html += '<table class="ewa-table"><thead><tr>'
        + '<th>#</th><th>脚本名称</th><th>类型</th>'
        + '<th>脚本预览</th><th>操作</th>'
        + '</tr></thead><tbody>';
    if (data.scriptSets && data.scriptSets.length > 0) {
        for (var i = 0; i < data.scriptSets.length; i++) {
            var sc = data.scriptSets[i];
            html += '<tr>'
                + '<td>' + (i+1) + '</td>'
                + '<td><b>' + sc.name + '</b></td>'
                + '<td>' + sc.scriptType + '</td>'
                + '<td><pre style="max-height:60px;overflow:hidden;margin:0;">' + (sc.scriptPreview||'') + '</pre></td>'
                + '<td>'
                + '<button onclick="editScriptSet(\''+sc.name+'\')">编辑</button>'
                + '</td></tr>';
        }
    } else {
        html += '<tr><td colspan="5" style="color:#999;">无 ScriptSet 配置</td></tr>';
    }
    html += '</tbody></table>';

    $('#ewa_list_body').html(html);
}
addEvent(window, 'load', loadData);

Set.Top:
var gXmlPath = '@XML_PATH';
var gItemName = '@ITEM_NAME';
var gSqlName = '@SQL_NAME';
var gOldSqlName = gSqlName;

function goBack() {
    var url = './?XMLNAME=/ewa/UPDATE_CFG.xml&ITEMNAME=SqlCfg.LF.M&XML_PATH=' + encodeURIComponent(gXmlPath) + '&ITEM_NAME=' + encodeURIComponent(gItemName);
    EWA.F.jump(url);
}

Set.Bottom:
function init_sql_form() {
    if (gSqlName) {
        $.getJSON('./?XMLNAME=/ewa/UPDATE_CFG.xml&ITEMNAME=SqlCfg.F.NM&EWA_AJAX=json', {
            method: 'getSqlSet',
            XML_PATH: gXmlPath,
            ITEM_NAME: gItemName,
            SQL_NAME: gSqlName
        }, function(res) {
            if (res && res.success && res.data) {
                $('#lbl_sql').text(res.data.name);
                $('#SQL_TYPE').val(res.data.sqlType || '');
                $('#TRANS_TYPE').val(res.data.transType || '');
                if (typeof EWA_setEditorContent === 'function') {
                    EWA_setEditorContent('SQL_CONTENT', res.data.sqlContent || '');
                } else {
                    $('#SQL_CONTENT').val(res.data.sqlContent || '');
                }
            }
        });
    }
}
function saveSql() {
    var name = $('#SQL_NAME').val();
    if (!name) { alert('SQL 名称不能为空'); return; }

    var sqlContent = '';
    if (typeof EWA_getEditorContent === 'function') {
        sqlContent = EWA_getEditorContent('SQL_CONTENT');
    } else {
        sqlContent = $('#SQL_CONTENT').val();
    }

    $.post('./?XMLNAME=/ewa/UPDATE_CFG.xml&ITEMNAME=SqlCfg.F.NM&EWA_AJAX=json', {
        method: 'saveSqlSet',
        XML_PATH: gXmlPath,
        ITEM_NAME: gItemName,
        SQL_NAME: name,
        OLD_SQL_NAME: gOldSqlName,
        SQL_TYPE: $('#SQL_TYPE').val(),
        TRANS_TYPE: $('#TRANS_TYPE').val(),
        SQL_CONTENT: sqlContent
    }, function(res) {
        if (res && res.success) {
            alert('保存成功');
            goBack();
        } else {
            alert('保存失败: ' + (res ? res.message : '未知错误'));
        }
    });
}
addEvent(window, 'load', init_sql_form);

