function saveScript() {
    var name = $('#SCRIPT_NAME').val();
    if (!name) { alert('脚本名称不能为空'); return; }

    var scriptContent = '';
    if (typeof EWA_getEditorContent === 'function') {
        scriptContent = EWA_getEditorContent('SCRIPT_CONTENT');
    } else {
        scriptContent = $('#SCRIPT_CONTENT').val();
    }

    $.post('./?XMLNAME=/ewa/UPDATE_CFG.xml&ITEMNAME=ScriptCfg.F.NM&EWA_AJAX=json', {
        method: 'saveScriptSet',
        XML_PATH: gXmlPath,
        ITEM_NAME: gItemName,
        SCRIPT_NAME: name,
        OLD_SCRIPT_NAME: gOldScriptName,
        SCRIPT_TYPE: $('#SCRIPT_TYPE').val(),
        SCRIPT_CONTENT: scriptContent
    }, function(res) {
        if (res && res.success) {
            alert('保存成功');
            goBack();
        } else {
            alert('保存失败: ' + (res ? res.message : '未知错误'));
        }
    });
}
